package main

import (
	"bufio"
	"fmt"
	"os"
	"strconv"
	"strings"
)

type Node struct {
	value int
	next  *Node
	prev  *Node
}

type DList struct {
	head *Node
	tail *Node
	size int
}

func NewDList() *DList {
	return &DList{}
}

func (l *DList) Size() int {
	return l.size
}

func (l *DList) String() string {
	if l.head == nil {
		return "[]"
	}

	values := make([]string, 0, l.size)
	for node := l.head; node != nil; node = node.next {
		values = append(values, strconv.Itoa(node.value))
	}
	return "[" + strings.Join(values, ", ") + "]"
}

func (l *DList) PushFront(value int) {
	node := &Node{value: value, next: l.head}
	if l.head != nil {
		l.head.prev = node
	}
	l.head = node
	if l.tail == nil {
		l.tail = node
	}
	l.size++
}

func (l *DList) PushBack(value int) {
	node := &Node{value: value, prev: l.tail}
	if l.tail != nil {
		l.tail.next = node
	}
	l.tail = node
	if l.head == nil {
		l.head = node
	}
	l.size++
}

func (l *DList) PopFront() {
	if l.head == nil {
		return
	}
	l.head = l.head.next
	if l.head != nil {
		l.head.prev = nil
	} else {
		l.tail = nil
	}
	l.size--
}

func (l *DList) PopBack() {
	if l.tail == nil {
		return
	}
	l.tail = l.tail.prev
	if l.tail != nil {
		l.tail.next = nil
	} else {
		l.head = nil
	}
	l.size--
}

func (l *DList) Clear() {
	l.head = nil
	l.tail = nil
	l.size = 0
}

func main() {
	scanner := bufio.NewScanner(os.Stdin)
	ll := NewDList()

	for {
		fmt.Print("$")
		if !scanner.Scan() {
			break
		}
		line := scanner.Text()
		fmt.Println(line)
		args := strings.Fields(line)

		if len(args) == 0 {
			continue
		}

		cmd := args[0]

		switch cmd {
		case "show":
			fmt.Println(ll.String())
		case "size":
			fmt.Println(ll.Size())
		case "push_back":
			for _, v := range args[1:] {
				num, err := strconv.Atoi(v)
				if err != nil {
					fmt.Println("fail: comando invalido")
					continue
				}
				ll.PushBack(num)
			}
		case "push_front":
			for _, v := range args[1:] {
				num, err := strconv.Atoi(v)
				if err != nil {
					fmt.Println("fail: comando invalido")
					continue
				}
				ll.PushFront(num)
			}
		case "pop_back":
			ll.PopBack()
		case "pop_front":
			ll.PopFront()
		case "clear":
			ll.Clear()
		case "end":
			return
		default:
			fmt.Println("fail: comando invalido")
		}
	}
}
